const Sudoku = () => {
  const initial = [
    [5,3,0,0,7,0,0,0,0],
    [6,0,0,1,9,5,0,0,0],
    [0,9,8,0,0,0,0,6,0],
    [8,0,0,0,6,0,0,0,3],
    [4,0,0,8,0,3,0,0,1],
    [7,0,0,0,2,0,0,0,6],
    [0,6,0,0,0,0,2,8,0],
    [0,0,0,4,1,9,0,0,5],
    [0,0,0,0,8,0,0,7,9]
  ];
  const solution = [
    [5,3,4,6,7,8,9,1,2],
    [6,7,2,1,9,5,3,4,8],
    [1,9,8,3,4,2,5,6,7],
    [8,5,9,7,6,1,4,2,3],
    [4,2,6,8,5,3,7,9,1],
    [7,1,3,9,2,4,8,5,6],
    [9,6,1,5,3,7,2,8,4],
    [2,8,7,4,1,9,6,3,5],
    [3,4,5,2,8,6,1,7,9]
  ];
  const [grid, setGrid] = React.useState(initial.map(r => [...r]));
  const [selected, setSelected] = React.useState(null);
  const [message, setMessage] = React.useState('');

  const handleCellClick = (r, c) => {
    if (initial[r][c] !== 0) return;
    setSelected({ r, c });
    setMessage('');
  };

  const handleNumber = (n) => {
    if (!selected) return;
    const newGrid = grid.map(r => [...r]);
    newGrid[selected.r][selected.c] = n;
    setGrid(newGrid);
  };

  const checkSolution = () => {
    for (let r = 0; r < 9; r++) {
      for (let c = 0; c < 9; c++) {
        if (grid[r][c] !== solution[r][c]) {
          setMessage('Not quite right. Keep trying!');
          return;
        }
      }
    }
    setMessage('Congratulations! Puzzle solved!');
  };

  const reset = () => {
    setGrid(initial.map(r => [...r]));
    setSelected(null);
    setMessage('');
  };

  return React.createElement('div', { style: { fontFamily: 'system-ui, sans-serif', padding: '16px', display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '12px', height: '100%', overflow: 'auto' } },
    React.createElement('h3', { style: { margin: 0, fontSize: '16px', fontWeight: 600, color: '#111827' } }, 'Sudoku'),
    React.createElement('div', { style: { display: 'grid', gridTemplateColumns: 'repeat(9, 32px)', gap: '1px', background: '#374151', padding: '2px', borderRadius: '4px' } },
      grid.map((row, r) => row.map((cell, c) => {
        const isFixed = initial[r][c] !== 0;
        const isSelected = selected && selected.r === r && selected.c === c;
        const thickRight = (c + 1) % 3 === 0 && c !== 8;
        const thickBottom = (r + 1) % 3 === 0 && r !== 8;
        return React.createElement('div', {
          key: r + '-' + c,
          onClick: () => handleCellClick(r, c),
          style: {
            width: '32px',
            height: '32px',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            fontSize: '16px',
            fontWeight: isFixed ? 700 : 500,
            background: isSelected ? '#bfdbfe' : '#fff',
            color: isFixed ? '#111827' : '#2563eb',
            cursor: isFixed ? 'default' : 'pointer',
            borderRight: thickRight ? '2px solid #374151' : 'none',
            borderBottom: thickBottom ? '2px solid #374151' : 'none'
          }
        }, cell || '');
      }))
    ),
    React.createElement('div', { style: { display: 'flex', gap: '6px' } },
      [1,2,3,4,5,6,7,8,9].map(n => React.createElement('button', {
        key: n,
        onClick: () => handleNumber(n),
        style: {
          width: '32px',
          height: '32px',
          borderRadius: '4px',
          border: '1px solid #d1d5db',
          background: '#f9fafb',
          fontSize: '15px',
          fontWeight: 600,
          color: '#111827',
          cursor: 'pointer'
        }
      }, n))
    ),
    React.createElement('div', { style: { display: 'flex', gap: '8px' } },
      React.createElement('button', { onClick: checkSolution, style: { fontSize: '12px', padding: '6px 14px', borderRadius: '4px', border: 'none', background: '#16a34a', color: '#fff', cursor: 'pointer', fontWeight: 600 } }, 'Check'),
      React.createElement('button', { onClick: reset, style: { fontSize: '12px', padding: '6px 14px', borderRadius: '4px', border: 'none', background: '#6b7280', color: '#fff', cursor: 'pointer', fontWeight: 600 } }, 'Reset')
    ),
    message && React.createElement('div', { style: { fontSize: '13px', fontWeight: 600, color: message.includes('Congratulations') ? '#16a34a' : '#dc2626', textAlign: 'center' } }, message)
  );
};
render(<Sudoku/>);
